query ($first: Int, $after: String) {
  store {
    id
    metafields (first: $first, after: $after) {
        edges {
                node {
                    id
                    description
                    key
                    namespace
                    permissionSet
                    resourceId
                    value
                    ownerClientId
                }
                    cursor
            }
        pageInfo {
            hasNextPage
            hasPreviousPage
            startCursor
            endCursor
        }
    }
  }
}

