mutation Webhook {
   webhook {
       createHttpsWebhook(
           input: {
               eventFilters: [
                   {
                       dataFilter: {
                           path: ["namespace"]
                           values: { stringValues: ["shipping"] }
                           delivery: EXCLUDE # will change to "NOT_IN
                       }
                   }
               ]
               destination: "https://b88a11bf-aa8a-44c7-8d13-0904515f8ceb.mock.pstmn.io/exclude"
               scope: "store/metafield/updated"
           }
       ) {
           webhook {
               destination
               clientId
               id
               scope
               status
           }
           errors {
               ... on AlreadyExistsError {
                   message
               }
               ... on ValidationError {
                   message
               }
           }
       }
   }
}

query Store2 {
   store {
       webhooks {
           pageInfo {
               hasNextPage
               hasPreviousPage
               startCursor
               endCursor
           }
           edges {
               cursor
               node {
                   clientId
                   createdAt
                   id
                   scope
                   status
                   updatedAt
                   eventFilters {
                       delivery
                   }
                   ... on HttpsWebhook {
                       destination
                       clientId
                       createdAt
                       id
                       scope
                       status
                       updatedAt
                       eventFilters {
                           delivery
                       }
                   }
               }
           }
       }
   }
}

mutation Metafield {
    metafield {
        reassignMetafieldsOwner(
            input: {
                newClientId: "{{client_id}}"
                metafieldIds: [
                  "bc/store/metafield/X" # id of metafield belonging to client 1 with value: testValue2
                ]
            }
        ) {
            metafieldIds
            errors {
                ... on EntityNotFoundError {
                    id
                    message
                }
                ... on EntityAlreadyExistsError {
                    id
                    message
                }
                ... on ValidationError {
                    message
                }
            }
        }
    }
}

